    ArrayList<Integer> below, above;
    below = new ArrayList<Integer>(arr.size());
    above = new ArrayList<Integer>(arr.size());
    for (Integer x : arr) {
        if (x < pivot) {
            below.add(x);
        } else if (x > pivot) {
            above.add(x);
        }
    }
    int num_less = below.size();
    int num_lessoreq = arr.size() - above.size();
    if (k < num_less) {
        return kth(below, k);
    } else if (k >= num_lessoreq) {
        return kth(above, k);
    } else {
            return pivot;
    }
}

